import { ChatOpenAI } from "langchain/chat_models/openai";
import { createOpenAIToolsAgent } from "langchain/agents";
import { TavilySearchResults } from "langchain/tools/tavily";
import { ChatPromptTemplate } from "langchain/prompts";

const llm = new ChatOpenAI({ modelName: "gpt-4o", temperature: 0 });
const tools = [new TavilySearchResults({ maxResults: 3 })];

const prompt = ChatPromptTemplate.fromMessages([
  ["system", "You are a world-class researcher. Use search tools to find recent information."],
  ["placeholder", "{input}"],
  ["placeholder", "{agent_scratchpad}"],
]);

const agent = await createOpenAIToolsAgent({ llm, tools, prompt });
const agentExecutor = new AgentExecutor({ agent, tools, maxIterations: 5 });

const result = await agentExecutor.call({
  input: "Latest developments in quantum computing as of 2024"
});
console.log(result.output);

from langchain_core.output_parsers import PydanticOutputParser
from langchain_core.pydantic_v1 import BaseModel, Field
from typing import List

class ResearchReport(BaseModel):
    summary: str = Field(description="Concise summary of findings")
    key_findings: List[str] = Field(description="Bullet points of main discoveries")
    sources: List[str] = Field(description="Citation URLs")
    confidence: str = Field(description="HIGH|MEDIUM|LOW")

parser = PydanticOutputParser(pydantic_object=ResearchReport)

report_prompt = ChatPromptTemplate.from_template(
    """Answer the research question in JSON format.

{format_instructions}

Question: {question}

Context: {context}"""
).partial(format_instructions=parser.get_format_instructions())

report_chain = report_prompt | llm | parser

structured_report = report_chain.invoke({
    "question": "Impact of AI on climate modeling?",
    "context": search_results
